import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface SongSegment {
  text: string;
  pitch: number; // 0.5 to 2.0 (Web Speech API range)
  rate: number;  // 0.5 to 2.0
  durationEstimate?: number; // Estimated duration in ms
}

export interface CompanySong {
  companyName: string;
  summary: string;
  lyrics: SongSegment[];
}

export enum AppState {
  IDLE = 'IDLE',
  LOADING = 'LOADING',
  READY = 'READY',
  PLAYING = 'PLAYING',
  ERROR = 'ERROR'
}

import { GoogleGenAI, Type } from "@google/genai";
import { CompanySong } from "../types";

const apiKey = process.env.API_KEY || '';
const ai = new GoogleGenAI({ apiKey });

export const generateCompanySong = async (url: string): Promise<CompanySong> => {
  try {
    const prompt = `
      I want to create a funny but inspiring "Corporate Anthem" song for a company found at this URL: ${url}.

      1. First, use Google Search to find the "About Us" page or homepage of this company to understand what they do, their mission, and their vibe.
      2. Then, compose a short song (approx 6-10 lines).
      3. For each line of the song, assign a 'pitch' value (between 0.1 and 2.0) to simulate a melody when spoken by a robot.
         - 1.0 is normal voice.
         - 0.5 is very deep.
         - 1.5 is high/excited.
         - vary the pitch to create a musical contour (e.g., start low, go high for chorus).
      4. Assign a 'rate' value (0.5 to 1.5) for speed.

      Return the result as a JSON object.
    `;

    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }],
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            companyName: { type: Type.STRING, description: "The name of the company found" },
            summary: { type: Type.STRING, description: "A one sentence summary of what they do" },
            lyrics: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  text: { type: Type.STRING, description: "The lyric text for this segment" },
                  pitch: { type: Type.NUMBER, description: "Pitch value (0.1 to 2.0)" },
                  rate: { type: Type.NUMBER, description: "Rate/Speed value (0.5 to 1.5)" }
                },
                required: ["text", "pitch", "rate"]
              }
            }
          },
          required: ["companyName", "summary", "lyrics"]
        }
      }
    });

    if (!response.text) {
      throw new Error("No response from Gemini");
    }

    const data = JSON.parse(response.text) as CompanySong;
    return data;

  } catch (error) {
    console.error("Error generating song:", error);
    throw error;
  }
};

import React, { useEffect, useState } from 'react';

interface VisualizerProps {
  isActive: boolean;
  pitch: number;
}

export const Visualizer: React.FC<VisualizerProps> = ({ isActive, pitch }) => {
  const [bars, setBars] = useState<number[]>(new Array(10).fill(10));

  useEffect(() => {
    let interval: NodeJS.Timeout;

    if (isActive) {
      interval = setInterval(() => {
        setBars(prev => prev.map(() => {
          // Generate height based on pitch and random fluctuation
          const baseHeight = pitch * 30; 
          return Math.max(10, Math.min(100, baseHeight + Math.random() * 40 - 20));
        }));
      }, 100);
    } else {
      setBars(new Array(10).fill(5));
    }

    return () => clearInterval(interval);
  }, [isActive, pitch]);

  return (
    <div className="flex gap-1 items-end h-32 justify-center py-4">
      {bars.map((height, i) => (
        <div
          key={i}
          className="w-3 bg-gradient-to-t from-purple-500 to-pink-400 rounded-t-full visualizer-bar"
          style={{ height: `${height}%`, opacity: isActive ? 1 : 0.3 }}
        />
      ))}
    </div>
  );
};

import React, { useEffect, useRef, useState, useCallback } from 'react';
import { SongSegment, CompanySong } from '../types';
import { Visualizer } from './Visualizer';
import { Play, Square, RotateCcw } from 'lucide-react';

interface PlayerProps {
  song: CompanySong;
  onReset: () => void;
}

export const Player: React.FC<PlayerProps> = ({ song, onReset }) => {
  const [currentLineIndex, setCurrentLineIndex] = useState<number>(-1);
  const [isPlaying, setIsPlaying] = useState(false);
  const synth = useRef<SpeechSynthesis>(window.speechSynthesis);
  const [voices, setVoices] = useState<SpeechSynthesisVoice[]>([]);

  // Load voices
  useEffect(() => {
    const loadVoices = () => {
      setVoices(synth.current.getVoices());
    };
    loadVoices();
    if (synth.current.onvoiceschanged !== undefined) {
      synth.current.onvoiceschanged = loadVoices;
    }
  }, []);

  const stop = useCallback(() => {
    synth.current.cancel();
    setIsPlaying(false);
    setCurrentLineIndex(-1);
  }, []);

  const playSong = useCallback(() => {
    if (voices.length === 0) return;

    setIsPlaying(true);
    synth.current.cancel(); // Clear any existing queue

    // Helper to queue a single segment
    const speakSegment = (index: number) => {
      if (index >= song.lyrics.length) {
        setIsPlaying(false);
        setCurrentLineIndex(-1);
        return;
      }

      const segment = song.lyrics[index];
      setCurrentLineIndex(index);

      const utterance = new SpeechSynthesisUtterance(segment.text);

      // Select a specific voice if available (prefer Google US English or similar)
      const preferredVoice = voices.find(v => v.name.includes('Google') && v.lang.includes('en-US')) || voices[0];
      if (preferredVoice) utterance.voice = preferredVoice;

      utterance.pitch = segment.pitch;
      utterance.rate = segment.rate;
      utterance.volume = 1;

      utterance.onend = () => {
        speakSegment(index + 1);
      };

      utterance.onerror = (e) => {
        console.error("Speech error", e);
        setIsPlaying(false);
      };

      synth.current.speak(utterance);
    };

    // Start with the first segment
    speakSegment(0);
  }, [song, voices]);

  // Clean up on unmount
  useEffect(() => {
    return () => {
      synth.current.cancel();
    };
  }, []);

  const currentPitch = currentLineIndex >= 0 ? song.lyrics[currentLineIndex].pitch : 1;

  return (
    <div className="w-full max-w-2xl mx-auto flex flex-col items-center animate-fade-in">
      <div className="text-center mb-8">
        <h2 className="text-3xl font-bold text-transparent bg-clip-text bg-gradient-to-r from-purple-400 to-pink-600 mb-2">
          {song.companyName}
        </h2>
        <p className="text-slate-400 text-sm max-w-md mx-auto italic">
          "{song.summary}"
        </p>
      </div>

      <div className="w-full bg-slate-800/50 backdrop-blur-sm rounded-3xl p-8 border border-slate-700 shadow-2xl relative overflow-hidden">
        {/* Dynamic Background Pulse based on pitch */}
        <div 
          className="absolute inset-0 bg-purple-500/10 pointer-events-none transition-opacity duration-200"
          style={{ opacity: isPlaying ? 0.2 : 0 }}
        />

        <Visualizer isActive={isPlaying} pitch={currentPitch} />

        <div className="h-48 flex items-center justify-center my-6 relative z-10">
            {currentLineIndex >= 0 ? (
                 <h3 className="text-2xl md:text-4xl font-black text-white text-center leading-tight drop-shadow-lg transition-all duration-300 transform scale-105">
                 {song.lyrics[currentLineIndex].text}
               </h3>
            ) : (
                <div className="text-slate-500 flex flex-col items-center">
                    <span className="text-4xl mb-2">🎵</span>
                    <span className="uppercase tracking-widest text-xs font-semibold">Ready to sing</span>
                </div>
            )}
        </div>

        {/* Lyrics Preview List */}
        <div className="mt-8 mb-8 space-y-2 h-32 overflow-y-auto custom-scrollbar border-t border-slate-700/50 pt-4 text-center">
            {song.lyrics.map((line, idx) => (
                <p 
                    key={idx} 
                    className={`text-sm transition-colors duration-300 ${
                        idx === currentLineIndex 
                        ? 'text-pink-400 font-bold scale-105' 
                        : 'text-slate-600'
                    }`}
                >
                    {line.text}
                </p>
            ))}
        </div>

        <div className="flex justify-center gap-4 mt-4">
          {!isPlaying ? (
            <button
              onClick={playSong}
              className="flex items-center gap-2 px-8 py-3 bg-pink-600 hover:bg-pink-500 text-white rounded-full font-bold transition-all transform hover:scale-105 shadow-lg shadow-pink-600/20"
            >
              <Play size={20} fill="currentColor" />
              PLAY ANTHEM
            </button>
          ) : (
            <button
              onClick={stop}
              className="flex items-center gap-2 px-8 py-3 bg-slate-700 hover:bg-slate-600 text-white rounded-full font-bold transition-all"
            >
              <Square size={20} fill="currentColor" />
              STOP
            </button>
          )}

          <button
            onClick={onReset}
            className="flex items-center gap-2 px-4 py-3 bg-transparent border border-slate-600 hover:bg-slate-700 text-slate-300 rounded-full font-medium transition-all"
            aria-label="Start Over"
          >
            <RotateCcw size={18} />
          </button>
        </div>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { generateCompanySong } from './services/geminiService';
import { AppState, CompanySong } from './types';
import { Player } from './components/Player';
import { Sparkles, Music2, Search, Loader2 } from 'lucide-react';

const App: React.FC = () => {
  const [url, setUrl] = useState('');
  const [state, setState] = useState<AppState>(AppState.IDLE);
  const [songData, setSongData] = useState<CompanySong | null>(null);
  const [error, setError] = useState<string>('');

  const handleGenerate = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!url.trim()) return;

    setState(AppState.LOADING);
    setError('');

    try {
      const song = await generateCompanySong(url);
      setSongData(song);
      setState(AppState.READY);
    } catch (err: any) {
      setError(err.message || "Failed to create song. Please try again.");
      setState(AppState.ERROR);
    }
  };

  const handleReset = () => {
    setState(AppState.IDLE);
    setSongData(null);
    setUrl('');
  };

  return (
    <div className="min-h-screen bg-[#0f172a] bg-[radial-gradient(ellipse_at_top,_var(--tw-gradient-stops))] from-slate-900 via-[#0f172a] to-black text-white selection:bg-pink-500/30">
      <div className="container mx-auto px-4 py-12 flex flex-col items-center min-h-screen justify-center">

        {/* Header Logo */}
        <div className="mb-12 text-center">
            <div className="inline-flex items-center justify-center w-16 h-16 rounded-2xl bg-gradient-to-br from-pink-500 to-purple-600 mb-6 shadow-2xl shadow-purple-500/20">
                <Music2 size={32} className="text-white" />
            </div>
            <h1 className="text-4xl md:text-6xl font-black tracking-tight mb-4">
                <span className="text-transparent bg-clip-text bg-gradient-to-r from-white to-slate-400">
                    Company
                </span>
                <span className="text-transparent bg-clip-text bg-gradient-to-r from-pink-400 to-purple-500 ml-2">
                    Anthem
                </span>
            </h1>
            <p className="text-slate-400 text-lg max-w-lg mx-auto leading-relaxed">
                Turn any corporate URL into a majestic (and slightly robotic) masterpiece.
            </p>
        </div>

        {/* Input State */}
        {(state === AppState.IDLE || state === AppState.ERROR || state === AppState.LOADING) && (
            <div className="w-full max-w-md animate-fade-in-up">
                <form onSubmit={handleGenerate} className="relative group">
                    <div className="absolute -inset-1 bg-gradient-to-r from-pink-600 to-purple-600 rounded-lg blur opacity-25 group-hover:opacity-75 transition duration-1000 group-hover:duration-200"></div>
                    <div className="relative flex items-center">
                        <input
                            type="text"
                            value={url}
                            onChange={(e) => setUrl(e.target.value)}
                            placeholder="e.g. apple.com, tesla.com"
                            className="w-full bg-slate-900 border border-slate-700 text-white placeholder-slate-500 px-6 py-4 rounded-l-lg focus:outline-none focus:ring-2 focus:ring-purple-500/50 focus:border-purple-500 transition-all text-lg"
                            disabled={state === AppState.LOADING}
                        />
                        <button
                            type="submit"
                            disabled={state === AppState.LOADING || !url}
                            className="bg-gradient-to-r from-pink-600 to-purple-600 hover:from-pink-500 hover:to-purple-500 text-white px-8 py-4 rounded-r-lg font-bold transition-all disabled:opacity-50 disabled:cursor-not-allowed flex items-center justify-center min-w-[100px]"
                        >
                            {state === AppState.LOADING ? (
                                <Loader2 className="animate-spin" />
                            ) : (
                                "GO"
                            )}
                        </button>
                    </div>
                </form>

                {state === AppState.LOADING && (
                    <div className="mt-8 text-center space-y-3">
                        <div className="flex justify-center gap-2">
                             <span className="w-2 h-2 bg-pink-500 rounded-full animate-bounce [animation-delay:-0.3s]"></span>
                             <span className="w-2 h-2 bg-purple-500 rounded-full animate-bounce [animation-delay:-0.15s]"></span>
                             <span className="w-2 h-2 bg-blue-500 rounded-full animate-bounce"></span>
                        </div>
                        <p className="text-slate-400 text-sm animate-pulse">Reading "About Us" page...</p>
                    </div>
                )}

                {state === AppState.ERROR && (
                    <div className="mt-6 p-4 bg-red-500/10 border border-red-500/20 text-red-400 rounded-lg text-sm text-center">
                        {error}
                    </div>
                )}
            </div>
        )}

        {/* Player State */}
        {state === AppState.READY && songData && (
            <Player song={songData} onReset={handleReset} />
        )}

        {/* Footer */}
        <div className="fixed bottom-4 text-xs text-slate-600">
            Powered by Google Gemini 2.0 Flash
        </div>
      </div>
    </div>
  );
};

export default App;

