      setBars(new Array(10).fill(5));
    }

    return () => {
      if (interval) clearInterval(interval);
    };
  }, [isActive, pitch]);

  return (
    <div className="flex gap-1 items-end h-32 justify-center py-4">
      {bars.map((height, i) => (
        <div
          key={i}
          className="w-3 bg-gradient-to-t from-purple-500 to-pink-400 rounded-t-full visualizer-bar"
          style={{ height: `${height}%`, opacity: isActive ? 1 : 0.3 }}
        />
      ))}
    </div>
  );
};

