import React, { useEffect, useRef, useState, useCallback } from 'react';
import { SongSegment, CompanySong } from '../types';
import { Visualizer } from './Visualizer';

interface PlayerProps {
  song: CompanySong;
  onReset: () => void;
}

export const Player: React.FC<PlayerProps> = ({ song, onReset }) => {
  const [currentLineIndex, setCurrentLineIndex] = useState<number>(-1);
  const [isPlaying, setIsPlaying] = useState(false);
  const synth = useRef<SpeechSynthesis>(window.speechSynthesis);
  const [voices, setVoices] = useState<SpeechSynthesisVoice[]>([]);

  useEffect(() => {
    const loadVoices = () => {
      setVoices(synth.current.getVoices());
    };
    loadVoices();
    if (synth.current.onvoiceschanged !== undefined) {
      synth.current.onvoiceschanged = loadVoices;
    }
  }, []);

  const stop = useCallback(() => {
    synth.current.cancel();
    setIsPlaying(false);
    setCurrentLineIndex(-1);
  }, []);

  const playSong = useCallback(() => {
    if (voices.length === 0) return;

    setIsPlaying(true);
    synth.current.cancel(); 

    const speakSegment = (index: number) => {
      if (index >= song.lyrics.length) {
        setIsPlaying(false);
        setCurrentLineIndex(-1);
        return;
      }

      const segment = song.lyrics[index];
      setCurrentLineIndex(index);

      const utterance = new SpeechSynthesisUtterance(segment.text);

      const preferredVoice = voices.find(v => v.name.includes('Google') && v.lang.includes('en-US')) || voices[0];
      if (preferredVoice) utterance.voice = preferredVoice;

      utterance.pitch = segment.pitch;
      utterance.rate = segment.rate;
      utterance.volume = 1;

      utterance.onend = () => {
        speakSegment(index + 1);
      };

      utterance.onerror = (e) => {
        console.error("Speech error", e);
        setIsPlaying(false);
      };

      synth.current.speak(utterance);
    };

    speakSegment(0);
  }, [song, voices]);

  useEffect(() => {
    return () => {
      synth.current.cancel();
    };
  }, []);

  const currentPitch = currentLineIndex >= 0 ? song.lyrics[currentLineIndex].pitch : 1;

  return (
    <div className="w-full mt-8 border-2 border-white p-4">
      <div className="text-center mb-6 border-b border-gray-600 pb-4">
        <h2 className="text-2xl text-cyan-400">
          {song.companyName}
        </h2>
        <p className="text-gray-500 text-sm italic">
          "{song.summary}"
        </p>
      </div>

      <div className="flex flex-col items-center">

        <Visualizer isActive={isPlaying} pitch={currentPitch} />

        <div className="h-32 flex items-center justify-center my-4 w-full bg-blue-900 border border-blue-500">
            {currentLineIndex >= 0 ? (
                 <h3 className="text-xl md:text-2xl text-white text-center px-4">
                 {song.lyrics[currentLineIndex].text}
               </h3>
            ) : (
                <div className="text-blue-300 text-sm">
                    [ READY TO SING ]
                </div>
            )}
        </div>

        <div className="w-full text-left mb-6 text-xs text-gray-500 border border-gray-800 p-2 h-32 overflow-y-auto font-mono">
            {song.lyrics.map((line, idx) => (
                <div 
                    key={idx} 
                    className={`${idx === currentLineIndex ? 'bg-white text-black' : ''}`}
                >
                    {idx + 1}. {line.text}
                </div>
            ))}
        </div>

        <div className="flex justify-center gap-4 w-full">
          {!isPlaying ? (
            <button
              onClick={playSong}
              className="bg-green-700 hover:bg-green-600 text-white border-2 border-green-400 px-6 py-2 shadow-[4px_4px_0px_0px_rgba(0,255,0,0.3)] active:shadow-none active:translate-y-1"
            >
              [ &gt; PLAY SONG ]
            </button>
          ) : (
            <button
              onClick={stop}
              className="bg-red-700 hover:bg-red-600 text-white border-2 border-red-400 px-6 py-2 shadow-[4px_4px_0px_0px_rgba(255,0,0,0.3)] active:shadow-none active:translate-y-1"
            >
              [ [] STOP ]
            </button>
          )}

          <button
            onClick={onReset}
            className="text-gray-400 hover:text-white underline text-sm"
          >
            Start Over
          </button>
        </div>
      </div>
    </div>
  );
};

import React, { useEffect, useState } from 'react';

interface VisualizerProps {
  isActive: boolean;
  pitch: number;
}

export const Visualizer: React.FC<VisualizerProps> = ({ isActive, pitch }) => {
  const [bars, setBars] = useState<number[]>(new Array(10).fill(10));

  useEffect(() => {
    let interval: ReturnType<typeof setInterval> | undefined;

    if (isActive) {
      interval = setInterval(() => {
        setBars(prev => prev.map(() => {
          // Generate height based on pitch and random fluctuation
          const baseHeight = pitch * 30; 
          return Math.max(10, Math.min(100, baseHeight + Math.random() * 40 - 20));
        }));
      }, 100);
    } else {
      setBars(new Array(10).fill(5));
    }

    return () => {
      if (interval) clearInterval(interval);
    };
  }, [isActive, pitch]);

  return (
    <div className="flex gap-2 items-end h-32 justify-center py-4 border border-dashed border-gray-700 w-full bg-black">
      {bars.map((height, i) => (
        <div
          key={i}
          className="w-4 bg-lime-500"
          style={{ height: `${height}%` }}
        />
      ))}
    </div>
  );
};

import React, { useEffect, useRef, useState, useCallback } from 'react';
import { SongSegment, CompanySong } from '../types';
import { Visualizer } from './Visualizer';

interface PlayerProps {
  song: CompanySong;
  onReset: () => void;
}

export const Player: React.FC<PlayerProps> = ({ song, onReset }) => {
  const [currentLineIndex, setCurrentLineIndex] = useState<number>(-1);
  const [isPlaying, setIsPlaying] = useState(false);
  const [charIndex, setCharIndex] = useState(0); // For karaoke painting

  const synth = useRef<SpeechSynthesis>(window.speechSynthesis);
  const audioCtx = useRef<AudioContext | null>(null);
  const bgmNodes = useRef<AudioNode[]>([]);
  const [voices, setVoices] = useState<SpeechSynthesisVoice[]>([]);

  useEffect(() => {
    const loadVoices = () => {
      setVoices(synth.current.getVoices());
    };
    loadVoices();
    if (synth.current.onvoiceschanged !== undefined) {
      synth.current.onvoiceschanged = loadVoices;
    }
  }, []);

  // Simple Retro BGM Synthesizer
  const startBGM = () => {
    audioCtx.current = new (window.AudioContext || (window as any).webkitAudioContext)();
    const ctx = audioCtx.current;
    const masterGain = ctx.createGain();
    masterGain.gain.value = 0.15; // Low volume for BGM
    masterGain.connect(ctx.destination);

    // Bass Loop
    const playBass = (time: number, note: number) => {
      const osc = ctx.createOscillator();
      const g = ctx.createGain();
      osc.type = 'square';
      osc.frequency.setValueAtTime(note, time);
      g.gain.setValueAtTime(0.5, time);
      g.gain.exponentialRampToValueAtTime(0.01, time + 0.4);
      osc.connect(g);
      g.connect(masterGain);
      osc.start(time);
      osc.stop(time + 0.5);
      bgmNodes.current.push(osc);
    };

    // Percussion Noise
    const playSnare = (time: number) => {
      const bufferSize = ctx.sampleRate * 0.1;
      const buffer = ctx.createBuffer(1, bufferSize, ctx.sampleRate);
      const data = buffer.getChannelData(0);
      for (let i = 0; i < bufferSize; i++) data[i] = Math.random() * 2 - 1;
      const noise = ctx.createBufferSource();
      noise.buffer = buffer;
      const filter = ctx.createBiquadFilter();
      filter.type = 'highpass';
      filter.frequency.value = 1000;
      const g = ctx.createGain();
      g.gain.setValueAtTime(0.3, time);
      g.gain.exponentialRampToValueAtTime(0.01, time + 0.1);
      noise.connect(filter);
      filter.connect(g);
      g.connect(masterGain);
      noise.start(time);
      bgmNodes.current.push(noise);
    };

    // Sequence (120 BPM)
    let nextNoteTime = ctx.currentTime;
    const schedule = () => {
      while (nextNoteTime < ctx.currentTime + 0.1) {
        const beat = Math.floor(nextNoteTime * 2) % 8;
        // Simple C-Major corporate loop
        const notes = [130.81, 130.81, 164.81, 164.81, 196.00, 196.00, 174.61, 146.83];
        playBass(nextNoteTime, notes[beat]);
        if (beat % 4 === 2) playSnare(nextNoteTime);
        nextNoteTime += 0.25;
      }
      if (isPlaying) requestAnimationFrame(schedule);
    };

    // Check if context is suspended (browser policy)
    if (ctx.state === 'suspended') ctx.resume();
    schedule();
  };

  const stopBGM = () => {
    bgmNodes.current.forEach(node => { try { (node as any).stop(); } catch(e){} });
    bgmNodes.current = [];
    if (audioCtx.current) {
      audioCtx.current.close();
      audioCtx.current = null;
    }
  };

  const stop = useCallback(() => {
    synth.current.cancel();
    stopBGM();
    setIsPlaying(false);
    setCurrentLineIndex(-1);
    setCharIndex(0);
  }, []);

  const playSong = useCallback(() => {
    if (voices.length === 0) return;

    setIsPlaying(true);
    setCharIndex(0);
    startBGM();
    synth.current.cancel(); 

    const speakSegment = (index: number) => {
      if (index >= song.lyrics.length) {
        setTimeout(() => stop(), 1000); // Wait a bit after last line
        return;
      }

      const segment = song.lyrics[index];
      setCurrentLineIndex(index);
      setCharIndex(0);

      const utterance = new SpeechSynthesisUtterance(segment.text);
      const preferredVoice = voices.find(v => v.name.includes('Google') && v.lang.includes('en-US')) || voices[0];
      if (preferredVoice) utterance.voice = preferredVoice;

      utterance.pitch = segment.pitch;
      utterance.rate = segment.rate;

      // The "Painting" Logic
      utterance.onboundary = (event) => {
        if (event.name === 'word') {
          setCharIndex(event.charIndex + event.charLength);
        }
      };

      utterance.onend = () => {
        speakSegment(index + 1);
      };

      utterance.onerror = (e) => {
        console.error("Speech error", e);
        stop();
      };

      synth.current.speak(utterance);
    };

    speakSegment(0);
  }, [song, voices, stop]);

  useEffect(() => {
    return () => {
      synth.current.cancel();
      stopBGM();
    };
  }, []);

  const currentPitch = currentLineIndex >= 0 ? song.lyrics[currentLineIndex].pitch : 1;

  return (
    <div className="w-full mt-4 border-4 border-double border-white p-4 bg-black shadow-[0_0_20px_rgba(0,255,255,0.2)]">
      <div className="text-center mb-4 bg-gray-900 p-2 border border-gray-700">
        <h2 className="text-2xl text-yellow-400 font-bold uppercase tracking-tighter">
           KARAOKE: {song.companyName}
        </h2>
        <p className="text-cyan-400 text-[10px] font-mono">
          SYSTEM_BGM_ACTIVE // PITCH: {currentPitch.toFixed(2)}
        </p>
      </div>

      <div className="flex flex-col items-center">

        <Visualizer isActive={isPlaying} pitch={currentPitch} />

        {/* Main Karaoke Screen */}
        <div className="h-40 flex flex-col items-center justify-center my-4 w-full bg-[#000080] border-4 border-gray-400 relative overflow-hidden shadow-inner">
            {/* Retro Scanline effect */}
            <div className="absolute inset-0 pointer-events-none opacity-10 bg-[linear-gradient(rgba(18,16,16,0)_50%,rgba(0,0,0,0.25)_50%),linear-gradient(90deg,rgba(255,0,0,0.06),rgba(0,255,0,0.02),rgba(0,0,255,0.06))] z-20 bg-[length:100%_2px,3px_100%]"></div>

            {currentLineIndex >= 0 ? (
                <div className="relative z-10 px-6 text-center">
                   {/* Background Text (White) */}
                   <h3 className="text-2xl md:text-4xl text-white font-black leading-tight">
                        {song.lyrics[currentLineIndex].text}
                   </h3>
                   {/* Foreground Painted Text (Yellow/Blue) */}
                   <h3 
                    className="text-2xl md:text-4xl text-yellow-300 font-black leading-tight absolute top-0 left-6 right-6 overflow-hidden transition-all duration-75 whitespace-nowrap"
                    style={{ 
                        width: `${(charIndex / song.lyrics[currentLineIndex].text.length) * 100}%`,
                        clipPath: 'inset(0 0 0 0)'
                    }}
                   >
                        {song.lyrics[currentLineIndex].text}
                   </h3>
                </div>
            ) : (
                <div className="text-yellow-500 text-xl animate-pulse font-bold italic">
                    INSERT URL TO START
                </div>
            )}
        </div>

        {/* Playlist Queue */}
        <div className="w-full text-left mb-6 text-[10px] text-gray-400 border border-gray-800 p-2 h-24 overflow-y-auto font-mono bg-black/50">
            <div className="text-gray-600 mb-1 border-b border-gray-800 pb-1">-- NEXT LINES --</div>
            {song.lyrics.map((line, idx) => (
                <div 
                    key={idx} 
                    className={`${idx === currentLineIndex ? 'text-lime-400 font-bold' : ''} ${idx < currentLineIndex ? 'opacity-30 line-through' : ''}`}
                >
                    [{idx.toString().padStart(2, '0')}] {line.text}
                </div>
            ))}
        </div>

        <div className="flex justify-center gap-6 w-full items-center">
          {!isPlaying ? (
            <button
              onClick={playSong}
              className="bg-red-600 hover:bg-red-500 text-white border-b-4 border-red-800 px-10 py-3 font-black text-xl active:border-b-0 active:translate-y-1 transition-all"
            >
              START
            </button>
          ) : (
            <button
              onClick={stop}
              className="bg-yellow-600 hover:bg-yellow-500 text-black border-b-4 border-yellow-800 px-10 py-3 font-black text-xl active:border-b-0 active:translate-y-1 transition-all"
            >
              STOP
            </button>
          )}

          <button
            onClick={onReset}
            className="text-gray-500 hover:text-white underline text-xs decoration-dotted"
          >
            [EJECT]
          </button>
        </div>
      </div>
    </div>
  );
};

