export const generateCompanySong = async (url: string): Promise<CompanySong> => {
  try {
    const prompt = `
      Create a 2000s-style corporate anthem for the company at: ${url}.

      1. Use Google Search to find the company's core values, products, or mission.
      2. Compose 8-10 catchy karaoke lines.
      3. For each line, assign a 'pitch' value from 0.5 (Low Bass) to 2.0 (High Soprano).
         - IMPORTANT: Vary the pitches significantly line-by-line to create a "melody" (e.g., 0.8 -> 1.2 -> 1.5 -> 1.0).
         - Higher pitches (1.5+) for the "chorus" or exciting parts.
         - Lower pitches (0.7-0.9) for "verses".
      4. Assign a 'rate' value (0.8 to 1.2) for speed.

      Return a JSON object with companyName, summary, and lyrics (array of {text, pitch, rate}).
    `;

    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }],
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            companyName: { type: Type.STRING },
            summary: { type: Type.STRING },
            lyrics: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  text: { type: Type.STRING },
                  pitch: { type: Type.NUMBER, description: "Pitch value (0.5 to 2.0)" },
                  rate: { type: Type.NUMBER, description: "Rate value (0.8 to 1.2)" }
                },
                required: ["text", "pitch", "rate"]
              }
            }
          },
          required: ["companyName", "summary", "lyrics"]
        }
      }
    });

    if (!response.text) {
      throw new Error("No response from Gemini");
    }

    return JSON.parse(response.text) as CompanySong;

  } catch (error) {
    console.error("Error generating song:", error);
    throw error;
  }
};

import React, { useEffect, useRef, useState, useCallback } from 'react';
import { SongSegment, CompanySong } from '../types';
import { Visualizer } from './Visualizer';

interface PlayerProps {
  song: CompanySong;
  onReset: () => void;
}

export const Player: React.FC<PlayerProps> = ({ song, onReset }) => {
  const [currentLineIndex, setCurrentLineIndex] = useState<number>(-1);
  const [isPlaying, setIsPlaying] = useState(false);
  const [charIndex, setCharIndex] = useState(0);

  const synth = useRef<SpeechSynthesis>(window.speechSynthesis);
  const audioCtx = useRef<AudioContext | null>(null);
  const isPlayingRef = useRef(false);
  const [voices, setVoices] = useState<SpeechSynthesisVoice[]>([]);

  useEffect(() => {
    const loadVoices = () => {
      setVoices(synth.current.getVoices());
    };
    loadVoices();
    if (synth.current.onvoiceschanged !== undefined) {
      synth.current.onvoiceschanged = loadVoices;
    }
  }, []);

  const startBGM = () => {
    if (!audioCtx.current) {
      audioCtx.current = new (window.AudioContext || (window as any).webkitAudioContext)();
    }
    const ctx = audioCtx.current;
    if (ctx.state === 'suspended') ctx.resume();

    const masterGain = ctx.createGain();
    masterGain.gain.value = 0.25; // Louder BGM
    masterGain.connect(ctx.destination);

    const playTone = (freq: number, time: number, duration: number, type: OscillatorType = 'square') => {
      const osc = ctx.createOscillator();
      const g = ctx.createGain();
      osc.type = type;
      osc.frequency.setValueAtTime(freq, time);
      g.gain.setValueAtTime(0.4, time);
      g.gain.exponentialRampToValueAtTime(0.01, time + duration);
      osc.connect(g);
      g.connect(masterGain);
      osc.start(time);
      osc.stop(time + duration);
    };

    const playNoise = (time: number, duration: number, lowFreq = 1000) => {
      const bufferSize = ctx.sampleRate * duration;
      const buffer = ctx.createBuffer(1, bufferSize, ctx.sampleRate);
      const data = buffer.getChannelData(0);
      for (let i = 0; i < bufferSize; i++) data[i] = Math.random() * 2 - 1;
      const source = ctx.createBufferSource();
      source.buffer = buffer;
      const filter = ctx.createBiquadFilter();
      filter.type = 'highpass';
      filter.frequency.value = lowFreq;
      const g = ctx.createGain();
      g.gain.setValueAtTime(0.2, time);
      g.gain.exponentialRampToValueAtTime(0.01, time + duration);
      source.connect(filter);
      filter.connect(g);
      g.connect(masterGain);
      source.start(time);
    };

    let nextBeatTime = ctx.currentTime;
    const scheduleLoop = () => {
      if (!isPlayingRef.current) return;

      while (nextBeatTime < ctx.currentTime + 0.1) {
        const beat = Math.floor(nextBeatTime * 4) % 16;

        // Bassline (Classic Corporate Rave)
        const bassNotes = [65.41, 65.41, 77.78, 65.41, 98.00, 65.41, 87.31, 65.41];
        if (beat % 2 === 0) {
           playTone(bassNotes[(beat/2) % 8], nextBeatTime, 0.2, 'sawtooth');
        }

        // Percussion
        if (beat % 4 === 0) playNoise(nextBeatTime, 0.1, 100); // Kick feel
        if (beat % 8 === 4) playNoise(nextBeatTime, 0.15, 2000); // Snare
        if (beat % 2 === 1) playNoise(nextBeatTime, 0.05, 8000); // Hi-hat

        nextBeatTime += 0.125; // 120 BPM (1/16th notes)
      }
      requestAnimationFrame(scheduleLoop);
    };

    scheduleLoop();
  };

  const stop = useCallback(() => {
    synth.current.cancel();
    isPlayingRef.current = false;
    setIsPlaying(false);
    setCurrentLineIndex(-1);
    setCharIndex(0);
    if (audioCtx.current) {
      audioCtx.current.close();
      audioCtx.current = null;
    }
  }, []);

  const playSong = useCallback(() => {
    if (voices.length === 0) return;

    isPlayingRef.current = true;
    setIsPlaying(true);
    setCharIndex(0);
    startBGM();

    const speakSegment = (index: number) => {
      if (!isPlayingRef.current) return;
      if (index >= song.lyrics.length) {
        setTimeout(() => stop(), 2000);
        return;
      }

      const segment = song.lyrics[index];
      setCurrentLineIndex(index);
      setCharIndex(0);

      const utterance = new SpeechSynthesisUtterance(segment.text);
      const preferredVoice = voices.find(v => v.name.includes('Google') && v.lang.includes('en-US')) || voices[0];
      if (preferredVoice) utterance.voice = preferredVoice;

      // MELODIC PITCH: Gemini provides the variation
      utterance.pitch = segment.pitch;
      utterance.rate = segment.rate || 1.0;

      utterance.onboundary = (event) => {
        if (event.name === 'word') {
          setCharIndex(event.charIndex + event.charLength);
        }
      };

      utterance.onend = () => {
        // Short pause between musical lines
        setTimeout(() => speakSegment(index + 1), 300);
      };

      utterance.onerror = () => stop();
      synth.current.speak(utterance);
    };

    speakSegment(0);
  }, [song, voices, stop]);

  useEffect(() => {
    return () => {
      synth.current.cancel();
      isPlayingRef.current = false;
    };
  }, []);

  const currentPitch = currentLineIndex >= 0 ? song.lyrics[currentLineIndex].pitch : 1;

  return (
    <div className="w-full mt-4 border-4 border-double border-white p-4 bg-black shadow-[0_0_30px_rgba(255,255,0,0.2)]">
      <div className="text-center mb-4 bg-zinc-900 p-2 border border-zinc-700">
        <h2 className="text-2xl text-yellow-400 font-black uppercase tracking-tighter italic">
           NOW SINGING: {song.companyName}
        </h2>
        <p className="text-lime-400 text-[10px] font-mono animate-pulse">
           BGM_LOOP_ACTIVE // FREQ_MOD: {(currentPitch * 100).toFixed(0)}Hz
        </p>
      </div>

      <div className="flex flex-col items-center">

        <Visualizer isActive={isPlaying} pitch={currentPitch} />

        <div className="h-44 flex flex-col items-center justify-center my-4 w-full bg-[#0000AA] border-4 border-zinc-500 relative overflow-hidden">
            <div className="absolute inset-0 pointer-events-none opacity-20 bg-[linear-gradient(rgba(18,16,16,0)_50%,rgba(0,0,0,0.5)_50%),linear-gradient(90deg,rgba(255,0,0,0.06),rgba(0,255,0,0.02),rgba(0,0,255,0.06))] z-20 bg-[length:100%_4px,4px_100%]"></div>

            {currentLineIndex >= 0 ? (
                <div className="relative z-10 px-8 text-center w-full">
                   <h3 className="text-3xl md:text-5xl text-white font-black leading-tight drop-shadow-[4px_4px_0px_rgba(0,0,0,1)] uppercase">
                        {song.lyrics[currentLineIndex].text}
                   </h3>
                   <h3 
                    className="text-3xl md:text-5xl text-yellow-300 font-black leading-tight absolute top-0 left-0 right-0 overflow-hidden transition-all duration-75 whitespace-nowrap drop-shadow-[4px_4px_0px_rgba(0,0,0,1)] uppercase px-8"
                    style={{ 
                        width: `${Math.min(100, (charIndex / song.lyrics[currentLineIndex].text.length) * 100)}%`,
                    }}
                   >
                        {song.lyrics[currentLineIndex].text}
                   </h3>
                </div>
            ) : (
                <div className="text-white text-2xl font-black animate-bounce tracking-widest">
                    [ READY ]
                </div>
            )}
        </div>

        <div className="w-full text-left mb-6 text-[10px] text-zinc-500 border border-zinc-800 p-2 h-24 overflow-y-auto font-mono bg-zinc-950">
            <div className="text-zinc-700 mb-1 border-b border-zinc-800 pb-1 uppercase">&gt;&gt; SONG_DATA_STREAM</div>
            {song.lyrics.map((line, idx) => (
                <div 
                    key={idx} 
                    className={`${idx === currentLineIndex ? 'text-white bg-blue-900 px-1' : ''} ${idx < currentLineIndex ? 'opacity-20' : ''}`}
                >
                    LINE_{idx.toString().padStart(2, '0')} [P:{line.pitch.toFixed(1)}] {line.text}
                </div>
            ))}
        </div>

        <div className="flex justify-center gap-6 w-full items-center">
          {!isPlaying ? (
            <button
              onClick={playSong}
              className="bg-red-600 hover:bg-red-500 text-white border-b-8 border-red-900 px-12 py-4 font-black text-2xl active:border-b-0 active:translate-y-2 transition-all shadow-xl"
            >
              START ANTHEM
            </button>
          ) : (
            <button
              onClick={stop}
              className="bg-zinc-700 hover:bg-zinc-600 text-white border-b-8 border-zinc-900 px-12 py-4 font-black text-2xl active:border-b-0 active:translate-y-2 transition-all shadow-xl"
            >
              ABORT
            </button>
          )}

          <button
            onClick={onReset}
            className="text-zinc-600 hover:text-white underline text-xs font-mono"
          >
            [ EJECT_TAPE ]
          </button>
        </div>
      </div>
    </div>
  );
};

export interface WordUnit {
  text: string;
  pitch: number; // 0.5 to 2.0
}

export interface SongSegment {
  words: WordUnit[];
  rate: number;
}

export interface CompanySong {
  companyName: string;
  summary: string;
  lyrics: SongSegment[];
}

export enum AppState {
  IDLE = 'IDLE',
  LOADING = 'LOADING',
  READY = 'READY',
  ERROR = 'ERROR'
}

import { GoogleGenAI, Type } from "@google/genai";
import { CompanySong } from "../types";

const apiKey = process.env.API_KEY || '';
const ai = new GoogleGenAI({ apiKey });

export const generateCompanySong = async (url: string): Promise<CompanySong> => {
  try {
    const prompt = `
      Create a 2000s-style corporate anthem for the company at: ${url}.

      1. Use Google Search to find the company's core values and mission.
      2. Compose 6-8 catchy lines.
      3. For EACH word in every line, assign a 'pitch' value from 0.5 to 2.0 to create a melody.
         - For example, a line "We are the best" could have pitches [0.8, 1.0, 1.2, 1.5].
         - Create musical intervals (e.g., jumps between 0.8 and 1.4) to make it sound like singing.
      4. Each line should be a 'SongSegment' containing an array of 'words'.

      Return a JSON object:
      {
        "companyName": "Name",
        "summary": "Short tagline",
        "lyrics": [
          { "words": [{"text": "Hello", "pitch": 1.2}, {"text": "World", "pitch": 1.5}], "rate": 1.0 }
        ]
      }
    `;

    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }],
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            companyName: { type: Type.STRING },
            summary: { type: Type.STRING },
            lyrics: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  words: {
                    type: Type.ARRAY,
                    items: {
                      type: Type.OBJECT,
                      properties: {
                        text: { type: Type.STRING },
                        pitch: { type: Type.NUMBER }
                      },
                      required: ["text", "pitch"]
                    }
                  },
                  rate: { type: Type.NUMBER }
                },
                required: ["words", "rate"]
              }
            }
          },
          required: ["companyName", "summary", "lyrics"]
        }
      }
    });

    if (!response.text) throw new Error("No response");
    return JSON.parse(response.text) as CompanySong;
  } catch (error) {
    console.error("Error:", error);
    throw error;
  }
};

import React, { useEffect, useRef, useState, useCallback } from 'react';
import { SongSegment, CompanySong, WordUnit } from '../types';
import { Visualizer } from './Visualizer';

interface PlayerProps {
  song: CompanySong;
  onReset: () => void;
}

export const Player: React.FC<PlayerProps> = ({ song, onReset }) => {
  const [currentLineIndex, setCurrentLineIndex] = useState<number>(-1);
  const [currentWordIndex, setCurrentWordIndex] = useState<number>(-1);
  const [isPlaying, setIsPlaying] = useState(false);

  const synth = useRef<SpeechSynthesis>(window.speechSynthesis);
  const audioCtx = useRef<AudioContext | null>(null);
  const isPlayingRef = useRef(false);
  const [voices, setVoices] = useState<SpeechSynthesisVoice[]>([]);

  useEffect(() => {
    const loadVoices = () => {
      setVoices(synth.current.getVoices().filter(v => v.lang.startsWith('en') || v.lang.startsWith('ko')));
    };
    loadVoices();
    if (synth.current.onvoiceschanged !== undefined) {
      synth.current.onvoiceschanged = loadVoices;
    }
  }, []);

  const startBGM = () => {
    if (!audioCtx.current) {
      audioCtx.current = new (window.AudioContext || (window as any).webkitAudioContext)();
    }
    const ctx = audioCtx.current;
    if (ctx.state === 'suspended') ctx.resume();

    const masterGain = ctx.createGain();
    masterGain.gain.value = 0.2;
    masterGain.connect(ctx.destination);

    const playTone = (freq: number, time: number, duration: number, type: OscillatorType = 'square') => {
      const osc = ctx.createOscillator();
      const g = ctx.createGain();
      osc.type = type;
      osc.frequency.setValueAtTime(freq, time);
      g.gain.setValueAtTime(0.3, time);
      g.gain.exponentialRampToValueAtTime(0.01, time + duration);
      osc.connect(g);
      g.connect(masterGain);
      osc.start(time);
      osc.stop(time + duration);
    };

    let nextBeatTime = ctx.currentTime;
    const scheduleLoop = () => {
      if (!isPlayingRef.current) return;
      while (nextBeatTime < ctx.currentTime + 0.1) {
        const beat = Math.floor(nextBeatTime * 4) % 16;
        const bass = [55, 55, 65, 55, 73, 55, 49, 55]; // A1, C2, D2, B1
        if (beat % 2 === 0) playTone(bass[(beat/2)%8], nextBeatTime, 0.2, 'sawtooth');
        nextBeatTime += 0.25;
      }
      requestAnimationFrame(scheduleLoop);
    };
    scheduleLoop();
  };

  const stopPlayback = useCallback(() => {
    synth.current.cancel();
    isPlayingRef.current = false;
    setIsPlaying(false);
    if (audioCtx.current) {
      audioCtx.current.close();
      audioCtx.current = null;
    }
  }, []);

  const playSong = useCallback(() => {
    if (voices.length === 0) return;
    isPlayingRef.current = true;
    setIsPlaying(true);
    startBGM();

    const singWord = (lineIdx: number, wordIdx: number) => {
      if (!isPlayingRef.current) return;

      // Check if finished
      if (lineIdx >= song.lyrics.length) {
        setTimeout(stopPlayback, 1000);
        return;
      }

      const currentLine = song.lyrics[lineIdx];

      // Move to next line if words exhausted
      if (wordIdx >= currentLine.words.length) {
        setCurrentWordIndex(-1);
        setTimeout(() => singWord(lineIdx + 1, 0), 400); // Line gap
        return;
      }

      setCurrentLineIndex(lineIdx);
      setCurrentWordIndex(wordIdx);

      const word = currentLine.words[wordIdx];
      const utterance = new SpeechSynthesisUtterance(word.text);

      const preferredVoice = voices.find(v => v.name.includes('Google') || v.name.includes('Premium')) || voices[0];
      utterance.voice = preferredVoice;
      utterance.pitch = word.pitch;
      utterance.rate = 1.1; // Slightly faster for word chunks

      utterance.onend = () => {
        singWord(lineIdx, wordIdx + 1);
      };

      utterance.onerror = () => stopPlayback();
      synth.current.speak(utterance);
    };

    singWord(0, 0);
  }, [song, voices, stopPlayback]);

  const togglePlay = () => {
    if (isPlaying) {
      stopPlayback();
    } else {
      playSong();
    }
  };

  const currentPitch = (currentLineIndex >= 0 && currentWordIndex >= 0) 
    ? song.lyrics[currentLineIndex].words[currentWordIndex].pitch 
    : 1;

  return (
    <div className="w-full mt-8 p-4 bg-black border-2 border-white">
      <div className="text-center mb-6">
        <h2 className="text-xl text-green-400 font-bold underline mb-1">
          {song.companyName} Anthem
        </h2>
        <p className="text-xs text-gray-500 italic">"{song.summary}"</p>
      </div>

      <Visualizer isActive={isPlaying} pitch={currentPitch} />

      {/* Karaoke Display */}
      <div className="my-6 p-8 bg-black border-4 border-gray-700 min-h-[160px] flex items-center justify-center relative shadow-[inset_0_0_20px_rgba(255,255,255,0.1)]">
        {currentLineIndex >= 0 ? (
          <div className="text-center">
             <div className="flex flex-wrap justify-center gap-x-3 text-3xl md:text-5xl font-bold uppercase tracking-tight">
               {song.lyrics[currentLineIndex].words.map((w, idx) => (
                 <span 
                  key={idx}
                  className={`transition-colors duration-100 ${idx <= currentWordIndex ? 'text-yellow-400' : 'text-white opacity-40'}`}
                  style={{ textShadow: idx <= currentWordIndex ? '0 0 10px #facc15' : 'none' }}
                 >
                   {w.text}
                 </span>
               ))}
             </div>
          </div>
        ) : (
          <div className="text-gray-600 animate-pulse text-2xl">[ STANDBY ]</div>
        )}
      </div>

      {/* Control Panel */}
      <div className="flex flex-col items-center gap-4">
        <div className="flex gap-4">
          <button
            onClick={togglePlay}
            className={`px-10 py-3 font-bold text-xl border-2 border-white shadow-[4px_4px_0px_0px_rgba(255,255,255,0.5)] active:shadow-none active:translate-x-1 active:translate-y-1 ${isPlaying ? 'bg-gray-800 text-white' : 'bg-white text-black'}`}
          >
            {isPlaying ? 'PAUSE' : 'PLAY'}
          </button>

          <button
            onClick={onReset}
            className="px-6 py-3 font-bold border-2 border-gray-600 text-gray-400 hover:text-white hover:border-white transition-colors"
          >
            NEW SONG
          </button>
        </div>

        <div className="w-full h-1 bg-gray-900 overflow-hidden mt-4">
           {isPlaying && <div className="h-full bg-green-500 animate-[progress_20s_linear_infinite]" style={{ width: '100%' }}></div>}
        </div>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { generateCompanySong } from './services/geminiService';
import { AppState, CompanySong } from './types';
import { Player } from './components/Player';

const App: React.FC = () => {
  const [url, setUrl] = useState('');
  const [state, setState] = useState<AppState>(AppState.IDLE);
  const [songData, setSongData] = useState<CompanySong | null>(null);
  const [error, setError] = useState<string>('');

  const handleGenerate = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!url.trim()) return;
    setState(AppState.LOADING);
    setError('');
    try {
      const song = await generateCompanySong(url);
      setSongData(song);
      setState(AppState.READY);
    } catch (err: any) {
      setError(err.message || "Failed to connect.");
      setState(AppState.ERROR);
    }
  };

  const handleReset = () => {
    setState(AppState.IDLE);
    setSongData(null);
    setUrl('');
  };

  return (
    <div className="min-h-screen p-4 flex flex-col items-center justify-center">
      <div className="max-w-3xl w-full text-center">

        {/* Reverted Header Style */}
        <h1 className="text-4xl md:text-6xl text-yellow-300 mb-2 underline decoration-wavy decoration-red-500 inline-block px-4">
           Corporate Anthem Generator 
        </h1>
        <p className="text-gray-500 text-xs mb-12 uppercase tracking-widest">
            The Internet's #1 Karaoke Machine (c) 2000
        </p>

        {state !== AppState.READY && (
          <div className="flex flex-col items-center">
            <form onSubmit={handleGenerate} className="flex flex-col sm:flex-row gap-2 items-center bg-zinc-900 border-2 border-zinc-700 p-4 w-full max-w-lg">
                <input
                    type="text"
                    value={url}
                    onChange={(e) => setUrl(e.target.value)}
                    placeholder="Enter URL (e.g. google.com)"
                    className="w-full bg-black border border-gray-600 text-white px-4 py-2 focus:outline-none focus:border-white rounded-none"
                    disabled={state === AppState.LOADING}
                />
                <button
                    type="submit"
                    disabled={state === AppState.LOADING || !url}
                    className="bg-white hover:bg-gray-200 text-black px-8 py-2 font-black disabled:opacity-50 transition-none whitespace-nowrap"
                >
                    {state === AppState.LOADING ? "WAIT..." : "GO!"}
                </button>
            </form>

            {state === AppState.LOADING && (
                <div className="mt-8 text-green-500 font-mono text-sm animate-pulse">
                    &gt; ACCESSING DATABASE...<br/>
                    &gt; ANALYZING DNA...<br/>
                    &gt; COMPOSING MELODY...
                </div>
            )}

            {error && <div className="mt-4 text-red-500 border border-red-500 p-2 text-xs">{error}</div>}
          </div>
        )}

        {state === AppState.READY && songData && (
            <Player song={songData} onReset={handleReset} />
        )}

      </div>
    </div>
  );
};

export default App;
